    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max in any subarray
    nums.sort((a, b) => a - b);

    // Try all possible subarrays that can be balanced
    let minRemovals = nums.length - 1; // Worst case: remove all but one

    for (let i = 0; i < nums.length; i++) {
        // Try to find the smallest j such that nums[j] * k >= nums[i]
        let j = i;
        while (j < nums.length && nums[j] * k < nums[i]) {
            j++;
        }

        // If we found such a j, then the subarray from i to j-1 is balanced
        if (j < nums.length) {
            // The number of elements in this subarray is j - i
            // So the number of elements to remove is nums.length - (j - i)
            minRemovals = Math.min(minRemovals, nums.length - (j - i));
        }
    }

    return minRemovals;
}

